import java.util.*;final class StructuredConcurrencyCancellationPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String code){super(code);this.code=code;}String code(){return code;}}
    @SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){List<Map<String,Object>>raw=(List<Map<String,Object>>)input.getOrDefault("children",List.of());List<String>names=new ArrayList<>();Map<String,Map<String,Object>>children=new HashMap<>();Map<String,String>states=new HashMap<>();for(Map<String,Object>child:raw){String name=String.valueOf(child.get("name"));if(children.putIfAbsent(name,child)!=null)throw new PatternException("duplicate_child");names.add(name);states.put(name,"pending");}List<String>order=((List<Object>)input.getOrDefault("completion_order",List.of())).stream().map(String::valueOf).toList();if(order.size()!=names.size()||new HashSet<>(order).size()!=order.size()||!new HashSet<>(order).equals(new HashSet<>(names)))throw new PatternException("invalid_completion_order");List<String>results=new ArrayList<>();String status="completed";int completed=0;Integer cancelAfter=input.containsKey("parent_cancel_after")?((Number)input.get("parent_cancel_after")).intValue():null;
        for(String name:order){if(cancelAfter!=null&&completed>=cancelAfter){status="cancelled";break;}Map<String,Object>child=children.get(name);String outcome=String.valueOf(child.get("outcome"));if(outcome.equals("success")){states.put(name,"completed");results.add(name+":"+child.get("value"));completed++;}else if(outcome.equals("failure")){states.put(name,"failed");status="failed";break;}else throw new PatternException("unknown_outcome");}if(!status.equals("completed"))for(String name:names)if(states.get(name).equals("pending"))states.put(name,"cancelled");List<String>childStates=names.stream().map(name->name+":"+states.get(name)).toList();return Map.of("parent_status",status,"child_states",childStates,"results",results,"joined_count",names.size(),"leaked",0);}}
